        private async Task AddProjectSightServiceAccountToPortfolioAsync(IDBHelper ignitionDB, IDBHelper portfolioDB, ExternalService service, Guid portfolioId, int? adminGroupId = null, CancellationToken cancellationToken = default)
        {
            // Exceptions are handled by the caller

            // if the user is in the portfolio, we are done
            if (portfolioDB.ExecuteScalarGeneric<bool>($"SELECT 1 FROM Users WHERE UserName = '{service.EndPointID}' AND Deleted = 0"))
            {
                return;
            }

            // Need to get the admin group id if it isn't set
            if (adminGroupId == null)
            {
                adminGroupId = UserGroupSystem.GetAdminUserGroupInternal(portfolioDB).Item1;
            }

            var trimbleId = Global.GuidFromDB(service.EndPointKey);

            // create the portfolio user
            var user = new UserMaintenance
            {
                UserName = service.EndPointID,
                FirstName = DataAccessSupport.PSA_FIRST_NAME,
                LastName = DataAccessSupport.PSA_LAST_NAME,
                UserID = trimbleId,
                GroupID = adminGroupId.Value,
                Hidden = true,
                GUID = trimbleId,
                AdminGroupID = adminGroupId.Value // ensure the user is identified as a portfolio admin
            };

            // ToDo: What to do with errors

            var error = new ErrorEncountered();

            await WriteUserInternalAsync(portfolioDB, user, error, cancellationToken);

            // Ensure the user is in ApplicationUsers.
            var ignitionUser = new UserIgnition
            {
                UserID = user.UserID,
                EMail = user.UserName,
                FirstName = user.FirstName,
                LastName = user.LastName,
                CompanyName = "Trimble",
                IsCompliant = true,
                TrimbleID = user.UserID
            };

            const string STORED_PROC_IGNITION = "s_enc_add_or_update_user";

            if (!await DataAccessSupport.UpdateBaseBusinessRecordAsync(this, ignitionDB, ignitionUser, STORED_PROC_IGNITION, error, cancellationToken))
            {
                return;
            }

            // Shouldn't happen, but just in case
            user.UserID = ignitionUser.UserID;
            user.GUID = ignitionUser.UserID;

            // add an entry for the user organization
            ReconcileUserOrganizationStatus(ignitionDB, portfolioId, user, true, null, error);
        }

